	private void OnSelectorPressed(string eventKey)
	{
		if (!string.Equals(_selectedEventKey, eventKey, StringComparison.Ordinal))
		{
			_selectedEventKey = eventKey;
			ShowLoadingState(eventKey);
			this.EventSelected?.Invoke(eventKey);
		}
	}

	private void TriggerRefresh()
	{
