		}
	}

	private void RequestDiscordClaim()
	{
		if (_currentState?.DiscordState != null)
		{
			if (!IsEventActiveNow(_currentState, DateTime.UtcNow))
			{
				SetError(Loc.GetString("pubg-events-error-event-not-active"));
			}
			else
			{
				this.ClaimRequested?.Invoke(_currentState.EventKey, "one_time", _currentState.DiscordState.ClaimKey);
			}
		}
	}

	public void UpdateHub(PubgEventsHubStateMessage hub, string? preferredEventKey = null)
	{
		_eventCards.Clear();
		_selectorEntries.Clear();
		((Control)EventSelectorRail).RemoveAllChildren();
		foreach (PubgEventCardInfo item in hub.Events.OrderBy((PubgEventCardInfo card) => card.SortOrder))
		{
			_eventCards[item.EventKey] = new EventCardMeta
			{
				EventKey = item.EventKey,
				Kind = item.Kind,
				TitleKey = item.TitleKey,
				DescriptionKey = item.DescriptionKey,
				SelectorIconPath = item.SelectorIconPath,
				SelectorBannerPath = item.SelectorBannerPath,
				SelectorAccentHex = item.SelectorAccentHex,
				StartAt = item.StartAt,
				EndAt = item.EndAt,
				SortOrder = item.SortOrder,
				HasClaimable = item.HasClaimable,
				RedDotOneTime = item.RedDotOneTime,
				RedDotTasks = item.RedDotTasks,
				RedDotMilestones = item.RedDotMilestones
			};
		}
		RebuildSelectorRail();
		string selectedEventKey = _selectedEventKey;
		_selectedEventKey = preferredEventKey ?? _selectedEventKey ?? _eventCards.Values.OrderBy((EventCardMeta card) => card.SortOrder).FirstOrDefault()?.EventKey;
		if (!string.IsNullOrWhiteSpace(_selectedEventKey) && !_eventCards.ContainsKey(_selectedEventKey))
		{
			_selectedEventKey = _eventCards.Values.OrderBy((EventCardMeta card) => card.SortOrder).FirstOrDefault()?.EventKey;
		}
		UpdateSelectorVisualState(DateTime.UtcNow);
		if (!string.IsNullOrEmpty(_selectedEventKey) && (!string.Equals(selectedEventKey, _selectedEventKey, StringComparison.Ordinal) || !string.Equals(_currentState?.EventKey, _selectedEventKey, StringComparison.Ordinal)))
		{
			ShowLoadingState(_selectedEventKey);
			this.EventSelected?.Invoke(_selectedEventKey);
		}
	}

	public void UpdateEventState(PubgEventDetailInfo state)
	{
		_currentState = state;
		_selectedEventKey = state.EventKey;
		if (_eventCards.TryGetValue(state.EventKey, out EventCardMeta value))
		{
			value.TitleKey = state.TitleKey;
			value.DescriptionKey = state.DescriptionKey;
			value.StartAt = state.StartAt;
			value.EndAt = state.EndAt;
			value.HasClaimable = state.HasClaimable;
			value.RedDotOneTime = state.RedDotOneTime;
			value.RedDotTasks = state.RedDotTasks;
			value.RedDotMilestones = state.RedDotMilestones;
			if (!string.IsNullOrWhiteSpace(state.SelectorIconPath))
			{
				value.SelectorIconPath = state.SelectorIconPath;
			}
			if (!string.IsNullOrWhiteSpace(state.SelectorBannerPath))
			{
				value.SelectorBannerPath = state.SelectorBannerPath;
			}
			if (!string.IsNullOrWhiteSpace(state.SelectorAccentHex))
			{
				value.SelectorAccentHex = state.SelectorAccentHex;
			}
		}
		else
		{
			_eventCards[state.EventKey] = new EventCardMeta
			{
				EventKey = state.EventKey,
				Kind = state.Kind,
				TitleKey = state.TitleKey,
				DescriptionKey = state.DescriptionKey,
				SelectorIconPath = state.SelectorIconPath,
				SelectorBannerPath = state.SelectorBannerPath,
				SelectorAccentHex = state.SelectorAccentHex,
				StartAt = state.StartAt,
				EndAt = state.EndAt,
				SortOrder = state.SortOrder,
				HasClaimable = state.HasClaimable,
				RedDotOneTime = state.RedDotOneTime,
				RedDotTasks = state.RedDotTasks,
				RedDotMilestones = state.RedDotMilestones
			};
			RebuildSelectorRail();
		}
		EventTitleLabel.Text = ResolveLoc(state.TitleKey);
		bool flag = IsCookieEvent(state.EventKey);
		string text = (flag ? Loc.GetString("pubg-events-cookie-support-description") : ResolveLoc(state.DescriptionKey));
		bool flag2 = state.MarsState != null && !flag;
		((Control)EventDescriptionLabel).Visible = !flag2;
		EventDescriptionLabel.Text = (flag2 ? string.Empty : text);
		UpdateEventTimingLabels(state.StartAt, state.EndAt);
		((Control)DiscordSection).Visible = state.DiscordState != null;
		((Control)MarsSection).Visible = state.MarsState != null;
		bool eventActive = IsEventActiveNow(state, DateTime.UtcNow);
		if (state.DiscordState != null)
		{
			RenderDiscord(state.DiscordState, eventActive);
		}
		if (state.MarsState != null)
		{
			RenderMars(state.MarsState, eventActive);
		}
		else
		{
			_marsPulseTargets.Clear();
			MarsTokenBalanceLabel.Text = string.Empty;
		}
		UpdateSelectorVisualState(DateTime.UtcNow);
	}

	private void RebuildSelectorRail()
	{
		_selectorEntries.Clear();
		((Control)EventSelectorRail).RemoveAllChildren();
		foreach (EventCardMeta item in _eventCards.Values.OrderBy((EventCardMeta item) => item.SortOrder))
		{
			SelectorEntryControls selectorEntryControls = CreateSelectorEntry(item);
			_selectorEntries[item.EventKey] = selectorEntryControls;
			((Control)EventSelectorRail).AddChild((Control)(object)selectorEntryControls.Button);
		}
	}

