	private void UpdateSelectorVisualState(DateTime nowUtc)
	{
		foreach (var (key, entry) in _selectorEntries)
		{
			if (_eventCards.TryGetValue(key, out EventCardMeta value))
			{
				UpdateSelectorEntryVisual(entry, value, nowUtc);
			}
		}
	}

