	private string BuildSelectorStatusText(EventCardMeta card, DateTime nowUtc)
	{
		DateTime dateTime = EnsureUtc(nowUtc);
		DateTime dateTime2 = EnsureUtc(card.StartAt);
		if (dateTime2 > dateTime)
		{
			TimeSpan timeSpan = dateTime2 - dateTime;
			if (timeSpan.TotalDays >= 1.0)
			{
				return Loc.GetString("pubg-prelobby-hub-event-card-starts-in-days", new(string, object)[2]
				{
					("days", (int)timeSpan.TotalDays),
					("hours", timeSpan.Hours)
				});
			}
			return Loc.GetString("pubg-prelobby-hub-event-card-starts-in-hours", new(string, object)[2]
			{
				("hours", Math.Max(1, (int)timeSpan.TotalHours)),
				("minutes", Math.Max(0, timeSpan.Minutes))
			});
		}
		if (card.HasClaimable)
		{
			return Loc.GetString("pubg-events-selector-claimable");
		}
		if (!card.EndAt.HasValue)
		{
			return Loc.GetString("pubg-events-selector-open");
		}
		TimeSpan timeSpan2 = EnsureUtc(card.EndAt.Value) - dateTime;
		if (timeSpan2 <= TimeSpan.Zero)
		{
			return Loc.GetString("pubg-events-selector-ended");
		}
		if (timeSpan2.TotalDays >= 1.0)
		{
			return Loc.GetString("pubg-prelobby-hub-event-card-time-left-days", new(string, object)[2]
			{
				("days", (int)timeSpan2.TotalDays),
				("hours", timeSpan2.Hours)
			});
		}
		return Loc.GetString("pubg-prelobby-hub-event-card-time-left-hours", new(string, object)[2]
		{
			("hours", Math.Max(1, (int)timeSpan2.TotalHours)),
			("minutes", Math.Max(0, timeSpan2.Minutes))
		});
	}

	private Texture? ResolveSelectorIconTexture(EventCardMeta card)
	{
		string path = ResolveSelectorIconPath(card);
		return TryGetTextureCached(path);
	}

	private Texture? ResolveSelectorBannerTexture(EventCardMeta card)
	{
		string text = ResolveSelectorBannerPath(card);
		if (string.IsNullOrWhiteSpace(text))
		{
			return null;
		}
		return TryGetTextureCached(text);
	}

	private string ResolveSelectorIconPath(EventCardMeta card)
	{
		if (!string.IsNullOrWhiteSpace(card.SelectorIconPath))
		{
			return card.SelectorIconPath;
		}
		if (string.Equals(card.EventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase))
		{
			return "/Textures/_PUBG/Lobby/Events/event_icon_discord.png";
		}
		if (string.Equals(card.EventKey, "mapper_cookie", StringComparison.OrdinalIgnoreCase))
		{
			return "/Textures/_PUBG/Lobby/Events/event_icon_cookie.png";
		}
		if (string.Equals(card.EventKey, "mars_opening", StringComparison.OrdinalIgnoreCase) || string.Equals(card.Kind, "mars", StringComparison.OrdinalIgnoreCase))
		{
			return "/Textures/_PUBG/Lobby/Events/event_icon_mars.png";
		}
		return "/Textures/_PUBG/Lobby/Events/event_icon_case.png";
	}

	private static string? ResolveSelectorBannerPath(EventCardMeta card)
	{
		if (!string.IsNullOrWhiteSpace(card.SelectorBannerPath))
		{
			return card.SelectorBannerPath;
		}
		return null;
	}

	private static Color ResolveSelectorAccent(EventCardMeta card)
	{
		//IL_0042: Unknown result type (might be due to invalid IL or missing references)
		//IL_0029: Unknown result type (might be due to invalid IL or missing references)
		//IL_005b: Unknown result type (might be due to invalid IL or missing references)
		//IL_0087: Unknown result type (might be due to invalid IL or missing references)
		//IL_008d: Unknown result type (might be due to invalid IL or missing references)
		if (!string.IsNullOrWhiteSpace(card.SelectorAccentHex))
		{
			Color? val = Color.TryFromHex((ReadOnlySpan<char>)card.SelectorAccentHex);
			if (val.HasValue)
			{
				return val.Value;
			}
		}
		if (string.Equals(card.EventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase))
		{
			return SelectorDiscordAccent;
		}
		if (string.Equals(card.EventKey, "mapper_cookie", StringComparison.OrdinalIgnoreCase))
		{
			return SelectorCookieAccent;
		}
		if (string.Equals(card.EventKey, "mars_opening", StringComparison.OrdinalIgnoreCase) || string.Equals(card.Kind, "mars", StringComparison.OrdinalIgnoreCase))
		{
			return SelectorMarsAccent;
		}
		return SelectorDefaultAccent;
	}

	private void RenderDiscord(PubgDiscordEventStateInfo state, bool eventActive)
	{
		DiscordDescriptionLabel.Text = Loc.GetString("pubg-events-discord-description");
		if (state.AlreadyClaimed)
		{
			DiscordStatusLabel.Text = Loc.GetString("pubg-events-discord-status-claimed");
		}
		else if (!state.Linked)
		{
			DiscordStatusLabel.Text = Loc.GetString("pubg-events-discord-status-not-linked");
		}
		else
		{
			DiscordStatusLabel.Text = Loc.GetString("pubg-events-discord-status-linked");
		}
		DiscordRewardLabel.Text = FormatReward(state.RewardType, state.RewardValue);
		DiscordClaimButton.Text = (state.AlreadyClaimed ? Loc.GetString("pubg-events-claimed") : Loc.GetString("pubg-events-claim"));
		((BaseButton)DiscordClaimButton).Disabled = !eventActive || !state.CanClaim;
	}

