			}
		}
		((Control)MarsLoginTaskList).RemoveAllChildren();
		if (!flag)
		{
			foreach (PubgMarsTaskInfo loginTask in state.LoginTasks)
			{
				((Control)MarsLoginTaskList).AddChild(CreateTaskRow(loginTask, eventActive, state.TaskRewardLabelKey));
			}
			if (state.LoginTasks.Count == 0)
			{
				((Control)MarsLoginTaskList).AddChild((Control)new Label
				{
					Text = Loc.GetString("pubg-events-empty"),
					FontColorOverride = Color.FromHex((ReadOnlySpan<char>)"#97A9C4", (Color?)null)
				});
			}
		}
		((Control)MarsChallengeTaskList).RemoveAllChildren();
		foreach (PubgMarsTaskInfo challengeTask in state.ChallengeTasks)
		{
			((Control)MarsChallengeTaskList).AddChild(flag ? CreateCookieTaskRow(challengeTask, eventActive, state.TaskRewardLabelKey) : CreateTaskRow(challengeTask, eventActive, state.TaskRewardLabelKey));
		}
		if (state.ChallengeTasks.Count == 0)
		{
			string text2 = (flag ? "pubg-events-cookie-no-challenges" : "pubg-events-empty");
			((Control)MarsChallengeTaskList).AddChild((Control)(flag ? ((object)CreateCookieEmptyChallengesPanel(text2)) : ((object)new Label
			{
				Text = Loc.GetString(text2),
				FontColorOverride = Color.FromHex((ReadOnlySpan<char>)"#97A9C4", (Color?)null)
			})));
		}
	}

	private void ConfigureMarsTabs(bool isCookieEvent)
	{
		if (isCookieEvent)
		{
			MarsTabContainer.SetTabVisible(0, false);
			MarsTabContainer.SetTabVisible(1, true);
			MarsTabContainer.SetTabTitle(1, Loc.GetString("pubg-events-cookie-tab-daily"));
			MarsTabContainer.CurrentTab = 1;
		}
		else
		{
			MarsTabContainer.SetTabVisible(0, true);
			MarsTabContainer.SetTabVisible(1, true);
			MarsTabContainer.SetTabTitle(0, Loc.GetString("pubg-events-tab-login"));
			MarsTabContainer.SetTabTitle(1, Loc.GetString("pubg-events-tab-challenge"));
		}
	}

	private void ApplyMarsLayoutMode(bool isCookieEvent)
	{
		if (isCookieEvent)
		{
			((Control)MarsProgressPanel).MinSize = new Vector2(0f, 360f);
			MarsMilestoneScroll.HScrollEnabled = false;
			MarsMilestoneScroll.VScrollEnabled = true;
			MarsMilestoneTrack.Orientation = (LayoutOrientation)1;
			MarsMilestoneTrack.SeparationOverride = 0;
			((Control)MarsMilestoneTrack).HorizontalExpand = true;
			((Control)MarsMilestoneTrack).VerticalExpand = true;
			((Control)MarsTasksPanel).MinSize = new Vector2(0f, 240f);
		}
		else
		{
			((Control)MarsProgressPanel).MinSize = new Vector2(0f, 320f);
			MarsMilestoneScroll.HScrollEnabled = true;
			MarsMilestoneScroll.VScrollEnabled = false;
			MarsMilestoneTrack.Orientation = (LayoutOrientation)0;
			MarsMilestoneTrack.SeparationOverride = 6;
			((Control)MarsMilestoneTrack).HorizontalExpand = true;
			((Control)MarsMilestoneTrack).VerticalExpand = false;
			((Control)MarsTasksPanel).MinSize = Vector2.Zero;
		}
	}

	private Texture? ResolveMainEventIcon(bool isCookieEvent)
	{
		string path = (isCookieEvent ? "/Textures/_PUBG/Lobby/Events/event_icon_cookie.png" : "/Textures/_PUBG/Lobby/Events/event_icon_mars.png");
		return TryGetTextureCached(path) ?? _fallbackTexture;
	}

