	private string FormatReward(string rewardType, string rewardValue)
	{
		return rewardType switch
		{
			"coins" => Loc.GetString("pubg-events-reward-coins", new(string, object)[1] { ("amount", rewardValue) }), 
			"scrap" => Loc.GetString("pubg-events-reward-scrap", new(string, object)[1] { ("amount", rewardValue) }), 
			"premiumCoins" => Loc.GetString("pubg-events-reward-premium", new(string, object)[1] { ("amount", rewardValue) }), 
			"item" => Loc.GetString("pubg-events-reward-item", new(string, object)[1] { ("id", ResolveRewardItemName(rewardValue)) }), 
			"recipe" => Loc.GetString("pubg-events-reward-recipe", new(string, object)[1] { ("id", rewardValue) }), 
			"emote" => Loc.GetString("pubg-events-reward-emote", new(string, object)[1] { ("id", rewardValue) }), 
			"permission" => Loc.GetString("pubg-events-reward-permission", new(string, object)[1] { ("id", rewardValue) }), 
			"tier" => Loc.GetString("pubg-events-reward-tier", new(string, object)[1] { ("id", rewardValue) }), 
			_ => Loc.GetString("pubg-events-reward-generic", new(string, object)[2]
			{
				("type", rewardType),
				("value", rewardValue)
			}), 
		};
	}

	private string GetMilestoneClaimButtonText(bool claimed, string rewardType, string rewardValue)
	{
		if (claimed)
		{
			return Loc.GetString("pubg-events-claimed");
		}
		bool flag;
		switch (rewardType)
		{
		case "coins":
		case "scrap":
		case "premiumCoins":
			flag = true;
			break;
		default:
			flag = false;
			break;
		}
		if (flag)
		{
			string item = FormatNumericRewardAmount(rewardValue);
			return Loc.GetString("pubg-events-claim-with-amount", new(string, object)[1] { ("amount", item) });
		}
		return Loc.GetString("pubg-events-claim");
	}

	private static string FormatNumericRewardAmount(string rawValue)
	{
		if (long.TryParse(rawValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out var result))
		{
			return result.ToString("N0", CultureInfo.InvariantCulture);
		}
		return rawValue;
	}

	public void SetError(string text)
	{
		ErrorLabel.Text = text;
	}

	public void ShowLoadingState(string eventKey)
	{
		_currentState = null;
		_selectedEventKey = eventKey;
		ErrorLabel.Text = string.Empty;
		if (_eventCards.TryGetValue(eventKey, out EventCardMeta value))
		{
			EventTitleLabel.Text = ResolveLoc(value.TitleKey, eventKey);
			EventDescriptionLabel.Text = ResolveLoc(value.DescriptionKey, Loc.GetString("pubg-events-loading"));
			UpdateEventTimingLabels(value.StartAt, value.EndAt);
		}
		else
		{
			EventTitleLabel.Text = eventKey;
			EventDescriptionLabel.Text = Loc.GetString("pubg-events-loading");
			EventPeriodLabel.Text = Loc.GetString("pubg-events-period-loading");
		}
		bool flag = string.Equals(eventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase);
		if (!flag && _eventCards.TryGetValue(eventKey, out EventCardMeta value2))
		{
			flag = string.Equals(value2.Kind, "one_time", StringComparison.OrdinalIgnoreCase);
		}
		bool flag2 = IsCookieEvent(eventKey);
		_marsPulseTargets.Clear();
		((Control)EventDescriptionLabel).Visible = flag || flag2;
		if (flag2)
		{
			EventDescriptionLabel.Text = Loc.GetString("pubg-events-cookie-support-description");
		}
		((Control)DiscordSection).Visible = flag;
		((Control)MarsSection).Visible = !flag;
		if (((Control)DiscordSection).Visible)
		{
			RenderDiscordLoading();
		}
		if (((Control)MarsSection).Visible)
		{
			RenderMarsLoading();
		}
		UpdateSelectorVisualState(DateTime.UtcNow);
	}

