	{
		_coinTexture = TryGetPrototypeIcon("SpaceCash") ?? TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_coin.png");
		_scrapTexture = TryGetPrototypeIcon("SheetSteel1") ?? TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_scrap.png");
		_premiumTexture = TryGetPrototypeIcon("MaterialDiamond1") ?? TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_premium.png");
