	private Texture? TryGetPrototypeIcon(string prototypeId)
	{
		EntityPrototype val = default(EntityPrototype);
		if (!_prototypeManager.TryIndex<EntityPrototype>(prototypeId, ref val))
		{
			return null;
		}
		return ((IDirectionalTextureProvider)_entityManager.System<SpriteSystem>().GetPrototypeIcon(val)).Default;
	}

	private Texture? GetRewardIcon(string rewardType, string rewardValue)
	{
		return (Texture?)(rewardType switch
		{
			"coins" => _coinTexture, 
			"scrap" => _scrapTexture, 
			"premiumCoins" => _premiumTexture, 
			"item" => TryGetPrototypeIcon(rewardValue) ?? _itemTexture ?? _fallbackTexture, 
			"recipe" => _itemTexture ?? _fallbackTexture, 
			"emote" => _itemTexture ?? _fallbackTexture, 
			"permission" => _itemTexture ?? _fallbackTexture, 
			"tier" => _itemTexture ?? _fallbackTexture, 
			_ => _fallbackTexture, 
		});
	}

	private string ResolveRewardItemName(string prototypeId)
	{
		EntityPrototype val = default(EntityPrototype);
		if (_prototypeManager.TryIndex<EntityPrototype>(prototypeId, ref val))
		{
			return val.Name;
		}
		return prototypeId;
	}

	private Texture? TryGetTexture(string path)
	{
		try
		{
			return _resources.GetResource<TextureResource>(path, true).Texture;
		}
		catch
		{
			return null;
		}
	}

	private Texture? TryGetTextureCached(string path)
	{
		if (_selectorTextureCache.TryGetValue(path, out Texture value))
		{
			return value;
		}
		value = TryGetTexture(path);
		_selectorTextureCache[path] = value;
		return value;
	}

	private bool UpdateMarsPulse(double deltaSeconds)
	{
		//IL_00d0: Unknown result type (might be due to invalid IL or missing references)
		//IL_00b9: Unknown result type (might be due to invalid IL or missing references)
		//IL_00e1: Unknown result type (might be due to invalid IL or missing references)
		//IL_00e7: Unknown result type (might be due to invalid IL or missing references)
		//IL_00ed: Unknown result type (might be due to invalid IL or missing references)
		//IL_00fe: Unknown result type (might be due to invalid IL or missing references)
		//IL_0104: Unknown result type (might be due to invalid IL or missing references)
		//IL_010b: Unknown result type (might be due to invalid IL or missing references)
		if (_marsPulseTargets.Count == 0)
		{
			return false;
		}
		_marsPulseTime += (float)deltaSeconds;
		for (int i = 0; i < _marsPulseTargets.Count; i++)
		{
			MarsPulseTarget marsPulseTarget = _marsPulseTargets[i];
			float num = 0.5f + MathF.Sin(_marsPulseTime * 3.4f + (float)i * 0.55f) * 0.5f;
			float num2 = 0.18f + num * 0.52f;
			float num3 = 0.05f + num * 0.16f;
			if (marsPulseTarget.Hovered)
			{
				num2 = Math.Clamp(num2 + 0.24f, 0f, 0.95f);
				num3 = Math.Clamp(num3 + 0.12f, 0f, 0.45f);
				marsPulseTarget.CardStyle.BorderThickness = new Thickness(2f);
			}
			else
			{
				marsPulseTarget.CardStyle.BorderThickness = new Thickness(1f);
			}
			marsPulseTarget.CardStyle.BorderColor = LerpColor(marsPulseTarget.BaseCardBorder, marsPulseTarget.PulseCardBorder, num2);
			marsPulseTarget.CardStyle.BackgroundColor = LerpColor(marsPulseTarget.BaseCardBackground, marsPulseTarget.PulseCardBackground, num3);
		}
		return true;
	}

