	private void UpdateEventTimingLabels(DateTime startAt, DateTime? endAt)
	{
		string item = FormatUtc(EnsureUtc(startAt));
		if (!endAt.HasValue)
		{
			EventPeriodLabel.Text = Loc.GetString("pubg-events-period-open", new(string, object)[1] { ("start", item) });
			return;
		}
		string item2 = FormatUtc(EnsureUtc(endAt.Value));
		EventPeriodLabel.Text = Loc.GetString("pubg-events-period-range", new(string, object)[2]
		{
			("start", item),
			("end", item2)
		});
	}

	private static string FormatUtc(DateTime utcDateTime)
	{
		string item = utcDateTime.ToString("dd.MM.yyyy HH:mm", CultureInfo.InvariantCulture);
		return Loc.GetString("pubg-events-time-utc", new(string, object)[1] { ("time", item) });
	}

	private static DateTime EnsureUtc(DateTime value)
	{
		if (value.Kind == DateTimeKind.Utc)
		{
			return value;
		}
		return DateTime.SpecifyKind(value, DateTimeKind.Utc);
	}

	private static bool IsCookieEvent(string? eventKey)
	{
		return string.Equals(eventKey, "mapper_cookie", StringComparison.OrdinalIgnoreCase);
	}

	private static bool IsEventActiveNow(PubgEventDetailInfo state, DateTime nowUtc)
	{
		if (!state.IsActive)
		{
			return false;
		}
		DateTime dateTime = EnsureUtc(nowUtc);
		if (EnsureUtc(state.StartAt) > dateTime)
		{
			return false;
		}
		if (state.EndAt.HasValue && EnsureUtc(state.EndAt.Value) <= dateTime)
		{
			return false;
		}
		return true;
	}

	private static float EaseOutCubic(float value)
	{
		float num = Math.Clamp(value, 0f, 1f);
		float num2 = 1f - num;
		return 1f - num2 * num2 * num2;
	}

	private void RenderDiscordLoading()
	{
		string text = Loc.GetString("pubg-events-loading");
		DiscordDescriptionLabel.Text = text;
		DiscordStatusLabel.Text = text;
		DiscordRewardLabel.Text = text;
		DiscordClaimButton.Text = text;
		((BaseButton)DiscordClaimButton).Disabled = true;
	}

	private void RenderMarsLoading()
	{
		string text = Loc.GetString("pubg-events-loading");
		bool flag = IsCookieEvent(_selectedEventKey);
		ConfigureMarsTabs(flag);
		ApplyMarsLayoutMode(flag);
		Texture texture = ResolveMainEventIcon(flag);
		MarsEventIcon.Texture = texture;
		MarsTokenIcon.Texture = texture;
		MarsRewardsTitleLabel.Text = (flag ? Loc.GetString("pubg-events-cookie-progress-title") : Loc.GetString("pubg-events-mars-rewards-title"));
		_marsPulseTargets.Clear();
		MarsTokenBalanceLabel.Text = text;
		((Control)MarsMilestoneTrack).RemoveAllChildren();
		if (flag)
		{
			((Control)MarsMilestoneTrack).AddChild(CreateLoadingCookieProgressTrack());
		}
		else
		{
			for (int i = 0; i < 8; i++)
			{
				if (i > 0)
				{
					((Control)MarsMilestoneTrack).AddChild(CreateMilestoneConnector(active: false));
				}
				((Control)MarsMilestoneTrack).AddChild(CreateLoadingMilestoneCard());
			}
		}
		((Control)MarsLoginTaskList).RemoveAllChildren();
		((Control)MarsChallengeTaskList).RemoveAllChildren();
		if (flag)
		{
			for (int j = 0; j < 4; j++)
			{
				((Control)MarsChallengeTaskList).AddChild(CreateLoadingTaskRow());
			}
			return;
		}
		for (int k = 0; k < 3; k++)
		{
			((Control)MarsLoginTaskList).AddChild(CreateLoadingTaskRow());
			((Control)MarsChallengeTaskList).AddChild(CreateLoadingTaskRow());
		}
	}

